"use client"

import { CursorifyProvider } from "@cursorify/react"
import { PhingerCursor } from "@cursorify/cursors"

export function CursorProvider({ children }: { children: React.ReactNode }) {
  return (
    <CursorifyProvider
      enabled
      cursor={PhingerCursor}
      delay={10}
      opacity={1}
      defaultCursorVisible={false}
      breakpoint={768}
    >
      {children}
    </CursorifyProvider>
  )
}
